{
  "name": "ArUco Sound Trigger",
  "description": "A PWA that detects ArUco markers and plays specific sounds from configurable sound packs.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface SoundPack {
  id: string;
  name: string;
}

export interface MarkerDetection {
  id: number;
  corners: { x: number; y: number }[];
}

export interface AppConfig {
  activePackId: string;
  debugMode: boolean;
}

// Extend window interface for OpenCV
declare global {
  interface Window {
    cv: any;
    cvLoaded: boolean;
  }
}

export const VALID_MARKER_IDS = [
  13, 30, 41, 42, 43, 49, 50, 54,
  63, 72, 108, 140, 164, 175, 194, 236
];

export const DEFAULT_PACK_ID = 'default';

// How often to scan for markers (ms)
// 100ms = 10 FPS detection (saves battery)
export const DETECTION_INTERVAL_MS = 100;

// Debounce sound playback (ms)
export const SOUND_COOLDOWN_MS = 2000;

// Default to a fallback list if packs.json fetch fails
export const FALLBACK_PACKS = [
  { id: 'default', name: 'Default Pack' },
  { id: 'animals', name: 'Animals' },
  { id: 'drums', name: 'Drums' }
];

import { VALID_MARKER_IDS } from '../constants';

class AudioService {
  private audioContext: AudioContext | null = null;
  private buffers: Map<string, AudioBuffer> = new Map(); // key: "packId-markerId"
  private lastPlayed: Map<number, number> = new Map(); // key: markerId, value: timestamp

  // Initialize AudioContext (must be called after user interaction)
  public async init() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }
  }

  // Construct the path for a sound file
  private getSoundUrl(packId: string, markerId: number): string {
    return `/soundpacks/${packId}/${markerId}.wav`;
  }

  // Preload a specific sound
  private async loadSound(packId: string, markerId: number): Promise<void> {
    const cacheKey = `${packId}-${markerId}`;
    if (this.buffers.has(cacheKey)) return;

    try {
      const response = await fetch(this.getSoundUrl(packId, markerId));
      if (!response.ok) throw new Error(`File missing: ${response.statusText}`);
      const arrayBuffer = await response.arrayBuffer();
      if (this.audioContext) {
        const audioBuffer = await this.audioContext.decodeAudioData(arrayBuffer);
        this.buffers.set(cacheKey, audioBuffer);
      }
    } catch (error) {
      console.warn(`[AudioService] Failed to load sound for ID ${markerId} in pack ${packId}`, error);
    }
  }

  // Preload all valid sounds for a pack
  public async preloadPack(packId: string) {
    if (!this.audioContext) await this.init();

    console.log(`[AudioService] Preloading pack: ${packId}`);
    const promises = VALID_MARKER_IDS.map(id => this.loadSound(packId, id));
    await Promise.allSettled(promises);
    console.log(`[AudioService] Pack ${packId} ready`);
  }

  // Play sound for a marker
  public play(packId: string, markerId: number) {
    if (!this.audioContext) return;
    if (!VALID_MARKER_IDS.includes(markerId)) return;

    const cacheKey = `${packId}-${markerId}`;
    const buffer = this.buffers.get(cacheKey);

    if (buffer) {
      const source = this.audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(this.audioContext.destination);
      source.start(0);
    } else {
      // Attempt just-in-time load and play (for fallback)
      this.loadSound(packId, markerId).then(() => {
        const lateBuffer = this.buffers.get(cacheKey);
        if (lateBuffer) {
           const source = this.audioContext.createBufferSource();
           source.buffer = lateBuffer;
           source.connect(this.audioContext.destination);
           source.start(0);
        }
      });
    }
  }
}

export const audioService = new AudioService();

import React, { useEffect, useState } from 'react';
import { SoundPack } from '../types';
import { FALLBACK_PACKS } from '../constants';

interface ControlPanelProps {
  currentPack: string;
  onPackChange: (packId: string) => void;
  debugMode: boolean;
  onDebugToggle: () => void;
  isCameraActive: boolean;
  onStartCamera: () => void;
}

export const ControlPanel: React.FC<ControlPanelProps> = ({
  currentPack,
  onPackChange,
  debugMode,
  onDebugToggle,
  isCameraActive,
  onStartCamera
}) => {
  const [packs, setPacks] = useState<SoundPack[]>(FALLBACK_PACKS);

  useEffect(() => {
    // Attempt to fetch packs.json, fallback to constant if fails
    fetch('/packs.json')
      .then(res => {
        if (res.ok) return res.json();
        throw new Error('No packs.json found');
      })
      .then(data => setPacks(data))
      .catch(() => {
        console.log('Using fallback pack list');
        // keep fallback
      });
  }, []);

  return (
    <div className="absolute bottom-0 left-0 right-0 bg-gray-900/90 backdrop-blur-md p-6 rounded-t-3xl z-20 border-t border-gray-700 shadow-2xl">
      <div className="max-w-md mx-auto space-y-4">

        {!isCameraActive ? (
          <button
            onClick={onStartCamera}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-semibold py-4 px-6 rounded-xl shadow-lg transition-all active:scale-95 text-lg"
          >
            Start Camera
          </button>
        ) : (
          <div className="flex flex-col gap-4">
            <div className="space-y-2">
              <label className="text-gray-400 text-xs uppercase tracking-wider font-semibold ml-1">Sound Pack</label>
              <div className="relative">
                <select
                  value={currentPack}
                  onChange={(e) => onPackChange(e.target.value)}
                  className="w-full appearance-none bg-gray-800 text-white border border-gray-600 rounded-xl py-3 px-4 pr-8 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                >
                  {packs.map(pack => (
                    <option key={pack.id} value={pack.id}>{pack.name}</option>
                  ))}
                </select>
                <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-gray-400">
                  <svg className="h-4 w-4 fill-current" viewBox="0 0 20 20">
                    <path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" />
                  </svg>
                </div>
              </div>
            </div>

            <div className="flex justify-between items-center mt-2">
               <span className="text-sm text-gray-400">
                 {isCameraActive ? "● Camera Active" : "○ Camera Paused"}
               </span>
               <button 
                 onClick={onDebugToggle}
                 className={`text-xs px-3 py-1 rounded-full border transition-colors ${debugMode ? 'bg-green-500/20 text-green-400 border-green-500/50' : 'bg-gray-800 text-gray-500 border-gray-700'}`}
               >
                 Debug Overlay
               </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { audioService } from '../services/audioService';
import { VALID_MARKER_IDS, DETECTION_INTERVAL_MS, SOUND_COOLDOWN_MS } from '../constants';
import { MarkerDetection } from '../types';

interface ScannerProps {
  isActive: boolean;
  currentPackId: string;
  debugMode: boolean;
  onError: (msg: string) => void;
}

export const Scanner: React.FC<ScannerProps> = ({ isActive, currentPackId, debugMode, onError }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const processingCanvasRef = useRef<HTMLCanvasElement | null>(null);

  const [cvReady, setCvReady] = useState(false);
  const [detectedIds, setDetectedIds] = useState<number[]>([]);

  const requestRef = useRef<number>();
  const lastScanTime = useRef<number>(0);
  const lastPlayedTime = useRef<Map<number, number>>(new Map());

  // Wait for OpenCV to load
  useEffect(() => {
    const checkCv = setInterval(() => {
      if (window.cv && window.cv.getBuildInformation) {
        console.log("OpenCV Loaded");
        setCvReady(true);
        clearInterval(checkCv);
      }
    }, 500);
    return () => clearInterval(checkCv);
  }, []);

  // Preload sounds when pack changes
  useEffect(() => {
    if (isActive) {
      audioService.preloadPack(currentPackId);
    }
  }, [currentPackId, isActive]);

  // Start Camera
  useEffect(() => {
    if (!isActive || !videoRef.current) return;

    const startStream = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: { ideal: 'environment' },
            width: { ideal: 1280 },
            height: { ideal: 720 }
          },
          audio: false,
        });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.play();
        }
      } catch (err) {
        console.error("Camera Error:", err);
        onError("Camera access denied or unavailable.");
      }
    };

    startStream();

    return () => {
      // Cleanup stream
      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [isActive, onError]);

  // Detection Loop
  const processFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current || !cvReady || !window.cv) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });

    if (video.readyState !== video.HAVE_ENOUGH_DATA || !ctx) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    // Match canvas size to video
    if (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
    }

    // Always clear previous drawings
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const now = performance.now();

    // Throttled detection logic
    if (now - lastScanTime.current > DETECTION_INTERVAL_MS) {
      lastScanTime.current = now;

      try {
        const cv = window.cv;

        // Use a small internal canvas for processing to improve performance
        if (!processingCanvasRef.current) {
           processingCanvasRef.current = document.createElement('canvas');
        }
        const pCanvas = processingCanvasRef.current;
        // Downscale for processing (e.g., max 480px width) - huge performance boost
        const scale = 480 / video.videoWidth;
        const pWidth = 480;
        const pHeight = video.videoHeight * scale;

        if (pCanvas.width !== pWidth) {
           pCanvas.width = pWidth;
           pCanvas.height = pHeight;
        }

        const pCtx = pCanvas.getContext('2d', { willReadFrequently: true });
        if (pCtx) {
           pCtx.drawImage(video, 0, 0, pWidth, pHeight);

           let src = cv.imread(pCanvas);
           let gray = new cv.Mat();
           cv.cvtColor(src, gray, cv.COLOR_RGBA2GRAY, 0);

           let dictionary = new cv.Dictionary(cv.DICT_4X4_250); // Matches standard ArUco 4x4
           let markerIds = new cv.Mat();
           let markerCorners = new cv.MatVector();
           let params = new cv.DetectorParameters();

           // Detection
           cv.detectMarkers(gray, dictionary, markerCorners, markerIds, params);

           const foundIds: number[] = [];

           if (markerIds.rows > 0) {
             for (let i = 0; i < markerIds.rows; i++) {
               const id = markerIds.data32S[i];

               // Filter: Only valid IDs
               if (VALID_MARKER_IDS.includes(id)) {
                 foundIds.push(id);

                 // Visualize if debug
                 if (debugMode) {
                   const corners = markerCorners.get(i);
                   // Scale corners back up to full resolution for display
                   const invScale = 1 / scale;

                   ctx.beginPath();
                   ctx.lineWidth = 4;
                   ctx.strokeStyle = '#00FF00'; // Green

                   // Draw rectangle
                   ctx.moveTo(corners.data32F[0] * invScale, corners.data32F[1] * invScale);
                   ctx.lineTo(corners.data32F[2] * invScale, corners.data32F[3] * invScale);
                   ctx.lineTo(corners.data32F[4] * invScale, corners.data32F[5] * invScale);
                   ctx.lineTo(corners.data32F[6] * invScale, corners.data32F[7] * invScale);
                   ctx.closePath();
                   ctx.stroke();

                   // Draw ID text
                   ctx.fillStyle = '#00FF00';
                   ctx.font = 'bold 24px Poppins';
                   ctx.fillText(`ID: ${id}`, corners.data32F[0] * invScale, corners.data32F[1] * invScale - 10);
                 }

                 // Play Sound Logic
                 const lastTime = lastPlayedTime.current.get(id) || 0;
                 if (now - lastTime > SOUND_COOLDOWN_MS) {
                   audioService.play(currentPackId, id);
                   lastPlayedTime.current.set(id, now);
                 }
               }
             }
           }

           setDetectedIds(foundIds);

           // Cleanup OpenCV memory
           src.delete();
           gray.delete();
           dictionary.delete();
           markerIds.delete();
           markerCorners.delete();
           params.delete();
        }
      } catch (e) {
        console.error("OpenCV Processing Error:", e);
      }
    }

    requestRef.current = requestAnimationFrame(processFrame);
  }, [cvReady, currentPackId, debugMode]);


  useEffect(() => {
    if (isActive && cvReady) {
       requestRef.current = requestAnimationFrame(processFrame);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isActive, cvReady, processFrame]);


  return (
    <div className="relative w-full h-full bg-black overflow-hidden flex items-center justify-center">
      {!isActive && (
        <div className="text-gray-500 text-center px-6">
          <p className="mb-2">Camera inactive.</p>
        </div>
      )}

      {!cvReady && isActive && (
         <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/80 text-white">
           <div className="text-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-white mx-auto mb-4"></div>
             <p>Loading Computer Vision...</p>
           </div>
         </div>
      )}

      {/* Actual Camera Feed (Hidden, we draw to canvas if needed, but video element is better for bg) */}
      <video 
        ref={videoRef} 
        className="absolute w-full h-full object-cover" 
        playsInline 
        muted 
      />

      {/* Overlay Canvas for Debug drawing */}
      <canvas 
        ref={canvasRef}
        className="absolute w-full h-full pointer-events-none object-cover"
      />

      {/* HUD Overlay for detection feedback */}
      <div className="absolute top-0 left-0 right-0 p-6 pt-safe z-10 pointer-events-none">
        <div className="flex justify-between items-start">
           <h1 className="text-white/80 font-bold text-xl drop-shadow-md">ArUco Scanner</h1>
           {detectedIds.length > 0 && (
             <div className="flex gap-2 flex-wrap justify-end">
               {detectedIds.map(id => (
                 <span key={id} className="bg-blue-500 text-white font-mono font-bold px-3 py-1 rounded-lg shadow-lg animate-pulse">
                   #{id}
                 </span>
               ))}
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Scanner } from './components/Scanner';
import { ControlPanel } from './components/ControlPanel';
import { DEFAULT_PACK_ID } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const [currentPack, setCurrentPack] = useState<string>(DEFAULT_PACK_ID);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [debugMode, setDebugMode] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleStartCamera = async () => {
    // Initialize audio context on user interaction
    await audioService.init();
    setIsCameraActive(true);
    setErrorMsg(null);
  };

  const handlePackChange = (newPackId: string) => {
    setCurrentPack(newPackId);
  };

  return (
    <div className="h-screen w-full flex flex-col bg-gray-900 overflow-hidden relative">

      {/* Error Toast */}
      {errorMsg && (
        <div className="absolute top-10 left-4 right-4 z-50 bg-red-500/90 text-white p-4 rounded-xl shadow-xl backdrop-blur">
          <p className="font-semibold">Error</p>
          <p className="text-sm opacity-90">{errorMsg}</p>
          <button 
            onClick={() => setErrorMsg(null)}
            className="absolute top-2 right-2 p-2 hover:bg-white/20 rounded-full"
          >
            ✕
          </button>
        </div>
      )}

      {/* Main Viewport */}
      <main className="flex-1 relative z-0">
        <Scanner 
          isActive={isCameraActive} 
          currentPackId={currentPack}
          debugMode={debugMode}
          onError={setErrorMsg}
        />
      </main>

      {/* Controls */}
      <ControlPanel 
        currentPack={currentPack}
        onPackChange={handlePackChange}
        debugMode={debugMode}
        onDebugToggle={() => setDebugMode(!debugMode)}
        isCameraActive={isCameraActive}
        onStartCamera={handleStartCamera}
      />
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// Basic Service Worker Registration for PWA support
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    // Note: You would typically generate this file via your build process (e.g., Vite/Webpack)
