           setDetectedIds(foundIds);

           src.delete();
           gray.delete();
           dictionary.delete();
           markerIds.delete();
           markerCorners.delete();
           params.delete();
        }
      } catch (e) {
        console.error("CV Error:", e);
      }
    }

    requestRef.current = requestAnimationFrame(processFrame);
  }, [cvReady, currentPackId, debugMode]);

  useEffect(() => {
    if (cvReady) {
       requestRef.current = requestAnimationFrame(processFrame);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [cvReady, processFrame]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">

      {/* Video Feed */}
      <video 
        ref={videoRef} 
        className="absolute w-full h-full object-cover" 
        playsInline 
        muted 
      />

      {/* Debug Canvas */}
      <canvas 
        ref={canvasRef}
        className="absolute w-full h-full pointer-events-none object-cover"
      />

      {/* Loading / Error States */}
      {(isLoading || !cvReady) && !cameraError && (
         <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900/40 backdrop-blur-sm z-30 text-white">
            <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-white mb-4"></div>
            <p className="text-sm font-medium">{!cvReady ? "Initializing Vision..." : "Starting Camera..."}</p>
         </div>
      )}

      {cameraError && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900 z-50 p-6 text-center">
           <p className="text-red-400 font-bold mb-2">Camera Error</p>
           <p className="text-gray-400 mb-6">{cameraError}</p>
           <button onClick={onBack} className="bg-white text-gray-900 px-6 py-2 rounded-full font-semibold">
             Go Back
           </button>
        </div>
      )}

      {/* HUD / Controls Overlay */}
      <div className="absolute top-0 left-0 right-0 z-40 p-4 pt-safe flex justify-between items-start bg-gradient-to-b from-black/60 to-transparent pb-12">

        {/* Back Button */}
        <button 
          onClick={onBack}
          className="w-10 h-10 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-full text-white hover:bg-white/20 transition-all active:scale-95"
          aria-label="Back"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6">
            <path fillRule="evenodd" d="M11.03 3.97a.75.75 0 010 1.06l-6.22 6.22H21a.75.75 0 010 1.5H4.81l6.22 6.22a.75.75 0 11-1.06 1.06l-7.5-7.5a.75.75 0 010-1.06l7.5-7.5a.75.75 0 011.06 0z" clipRule="evenodd" />
          </svg>
        </button>

        <div className="flex gap-3">
          {/* Debug Toggle */}
          <button
             onClick={() => setDebugMode(!debugMode)}
             className={`h-10 px-4 rounded-full flex items-center gap-2 backdrop-blur-md transition-all active:scale-95 font-medium text-sm ${debugMode ? 'bg-green-500 text-white' : 'bg-white/10 text-white/80 hover:bg-white/20'}`}
          >
             {debugMode ? (
                <>
                 <span className="w-2 h-2 rounded-full bg-white animate-pulse"></span>
                 Debug On
                </>
             ) : 'Debug'}
          </button>

          {/* Camera Switch */}
          <button 
            onClick={handleSwitchCamera}
            className="w-10 h-10 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-full text-white hover:bg-white/20 transition-all active:scale-95"
            aria-label="Switch Camera"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5">
              <path d="M15 11.25l-3-3m0 0l-3 3m3-3v7.5M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Home } from './components/Home';
import { Scanner } from './components/Scanner';
import { audioService } from './services/audioService';
import { FALLBACK_PACKS } from './constants';
import { SoundPack } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'scanner'>('home');
  const [currentPack, setCurrentPack] = useState<string>('default');
  const [packs, setPacks] = useState<SoundPack[]>(FALLBACK_PACKS);

  useEffect(() => {
    // Load pack configuration
    fetch('/packs.json')
      .then(res => res.ok ? res.json() : FALLBACK_PACKS)
      .then(setPacks)
      .catch(() => console.log("Using fallback packs"));
  }, []);

  const handlePackSelect = async (packId: string) => {
    // Initialize audio context on user gesture (tap)
    await audioService.init();

    setCurrentPack(packId);
    setView('scanner');
  };

  const handleBack = () => {
    setView('home');
  };

  return (
    <div className="h-screen w-full bg-gray-900 overflow-hidden relative">
      {view === 'home' ? (
        <Home 
          packs={packs} 
          onSelectPack={handlePackSelect} 
        />
      ) : (
        <Scanner 
          currentPackId={currentPack}
          onBack={handleBack}
        />
      )}
    </div>
  );
};

export default App;

import { VALID_MARKER_IDS } from '../constants';

class AudioService {
  private audioContext: AudioContext | null = null;
  private buffers: Map<string, AudioBuffer> = new Map(); // key: "packId-markerId"

  // Map IDs to musical notes (frequencies) for the fallback synthesizer
  // Pentatonic scale-ish mapping for pleasant sounds
  private idToFrequency: Map<number, number> = new Map();

  constructor() {
    // Generate frequencies based on IDs
    const baseFreq = 220; // A3
    VALID_MARKER_IDS.forEach((id, index) => {
      // Just a simple formula to spread frequencies out
      const freq = baseFreq * Math.pow(1.05946, index * 2); 
      this.idToFrequency.set(id, freq);
    });
  }

  // Initialize AudioContext (must be called after user interaction)
  public async init() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }
  }

  // Construct the path for a sound file
  private getSoundUrl(packId: string, markerId: number): string {
    return `/soundpacks/${packId}/${markerId}.wav`;
  }

  // Preload a specific sound
  private async loadSound(packId: string, markerId: number): Promise<void> {
    const cacheKey = `${packId}-${markerId}`;
    if (this.buffers.has(cacheKey)) return;

    try {
      const response = await fetch(this.getSoundUrl(packId, markerId));
      if (!response.ok) throw new Error(`File missing`);
      const arrayBuffer = await response.arrayBuffer();
      if (this.audioContext) {
        const audioBuffer = await this.audioContext.decodeAudioData(arrayBuffer);
        this.buffers.set(cacheKey, audioBuffer);
      }
    } catch (error) {
      // Silent fail - we will use synthesizer later
    }
  }

  // Preload all valid sounds for a pack
  public async preloadPack(packId: string) {
    if (!this.audioContext) await this.init();

    console.log(`[AudioService] Preloading pack: ${packId}`);
    const promises = VALID_MARKER_IDS.map(id => this.loadSound(packId, id));
    await Promise.allSettled(promises);
  }

  private playTone(markerId: number) {
    if (!this.audioContext) return;

    const osc = this.audioContext.createOscillator();
    const gainNode = this.audioContext.createGain();

    const freq = this.idToFrequency.get(markerId) || 440;

    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq, this.audioContext.currentTime);

    gainNode.gain.setValueAtTime(0.3, this.audioContext.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, this.audioContext.currentTime + 0.5);

    osc.connect(gainNode);
    gainNode.connect(this.audioContext.destination);

    osc.start();
    osc.stop(this.audioContext.currentTime + 0.5);
  }

  // Play sound for a marker
  public play(packId: string, markerId: number) {
    if (!this.audioContext) return;
    if (!VALID_MARKER_IDS.includes(markerId)) return;

    const cacheKey = `${packId}-${markerId}`;
    const buffer = this.buffers.get(cacheKey);

    if (buffer) {
      // Play File
      const source = this.audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(this.audioContext.destination);
      source.start(0);
    } else {
      // Fallback: Play Synth Tone
      console.log(`[Audio] Playing synth tone for ID ${markerId}`);
      this.playTone(markerId);
    }
  }
}

export const audioService = new AudioService();

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { audioService } from '../services/audioService';
import { VALID_MARKER_IDS, DETECTION_INTERVAL_MS, SOUND_COOLDOWN_MS } from '../constants';

interface ScannerProps {
  currentPackId: string;
  onBack: () => void;
}

export const Scanner: React.FC<ScannerProps> = ({ currentPackId, onBack }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const processingCanvasRef = useRef<HTMLCanvasElement | null>(null);

  const [cvReady, setCvReady] = useState(false);
  const [detectedIds, setDetectedIds] = useState<number[]>([]);
  const [debugMode, setDebugMode] = useState(true); // Default to true for testing
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('environment');
  const [lastTriggeredId, setLastTriggeredId] = useState<number | null>(null);

  // Debug Stats
  const [debugStats, setDebugStats] = useState({ fps: 0, processingTime: 0, resolution: '0x0' });

  const requestRef = useRef<number | null>(null);
  const lastScanTime = useRef<number>(0);
  const lastPlayedTime = useRef<Map<number, number>>(new Map());
  const streamRef = useRef<MediaStream | null>(null);

  // Initialize OpenCV
  useEffect(() => {
    const checkCv = setInterval(() => {
      if (window.cv && window.cv.getBuildInformation) {
        console.log("OpenCV Loaded successfully");
        console.log(window.cv.getBuildInformation());
        setCvReady(true);
        clearInterval(checkCv);
      }
    }, 500);
    return () => clearInterval(checkCv);
  }, []);

  // Preload sounds
  useEffect(() => {
    audioService.preloadPack(currentPackId);
  }, [currentPackId]);

  // Camera Management
  useEffect(() => {
    const startCamera = async () => {
      setCameraError(null);

      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }

      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: { ideal: facingMode },
            width: { ideal: 1920 }, // Request higher res
            height: { ideal: 1080 }
          },
          audio: false,
        });

        streamRef.current = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.onloadedmetadata = () => {
             videoRef.current?.play();
             // Update resolution stat
             if(videoRef.current) {
               setDebugStats(prev => ({ 
                 ...prev, 
                 resolution: `${videoRef.current?.videoWidth}x${videoRef.current?.videoHeight}` 
               }));
             }
          };
        }
      } catch (err) {
        console.error("Camera Error:", err);
        setCameraError("Camera access denied. Please allow permissions.");
      }
    };

    startCamera();

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [facingMode]);

  const handleSwitchCamera = () => {
    setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
  };

  // Main Detection Loop
  const processFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current || !cvReady || !window.cv) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });

    if (video.readyState !== video.HAVE_ENOUGH_DATA || !ctx) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    // Ensure HUD canvas matches video exact size
    if (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
    }

    // Clean canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const now = performance.now();

    // Throttle Detection
    if (now - lastScanTime.current > DETECTION_INTERVAL_MS) {
      const startTime = performance.now();
      lastScanTime.current = now;

      try {
        const cv = window.cv;
        if (!processingCanvasRef.current) processingCanvasRef.current = document.createElement('canvas');
        const pCanvas = processingCanvasRef.current;

        // Processing Resolution
        // Higher = better detection but slower. 640px is a good balance for mobile.
        const procWidth = 640;
        const scale = procWidth / video.videoWidth;
        const procHeight = video.videoHeight * scale;

        if (pCanvas.width !== procWidth) {
           pCanvas.width = procWidth;
           pCanvas.height = procHeight;
        }

        const pCtx = pCanvas.getContext('2d', { willReadFrequently: true });
        if (pCtx) {
           // Draw video to small processing canvas
           pCtx.drawImage(video, 0, 0, procWidth, procHeight);

           let src = cv.imread(pCanvas);
           let gray = new cv.Mat();
           cv.cvtColor(src, gray, cv.COLOR_RGBA2GRAY, 0);

           // Dictionary 4x4_250 is standard
           let dictionary = new cv.Dictionary(cv.DICT_4X4_250);
           let markerIds = new cv.Mat();
           let markerCorners = new cv.MatVector();
           let params = new cv.DetectorParameters();

           // Optional: tune parameters if detection is hard
           // params.adaptiveThreshWinSizeMin = 3;
           // params.adaptiveThreshWinSizeMax = 23;
           // params.adaptiveThreshWinSizeStep = 10;

           cv.detectMarkers(gray, dictionary, markerCorners, markerIds, params);

           const foundIds: number[] = [];

           if (markerIds.rows > 0) {
             for (let i = 0; i < markerIds.rows; i++) {
               const id = markerIds.data32S[i];

               // Draw ALL markers in debug mode to see if it detects wrong IDs
               if (debugMode || VALID_MARKER_IDS.includes(id)) {
                  const corners = markerCorners.get(i);
                  const invScale = 1 / scale;

                  // Get corners
                  const x0 = corners.data32F[0] * invScale;
                  const y0 = corners.data32F[1] * invScale;
                  const x1 = corners.data32F[2] * invScale;
                  const y1 = corners.data32F[3] * invScale;
                  const x2 = corners.data32F[4] * invScale;
                  const y2 = corners.data32F[5] * invScale;
                  const x3 = corners.data32F[6] * invScale;
                  const y3 = corners.data32F[7] * invScale;

                  // Draw Outline
                  ctx.beginPath();
                  ctx.lineWidth = VALID_MARKER_IDS.includes(id) ? 6 : 2;
                  ctx.strokeStyle = VALID_MARKER_IDS.includes(id) ? '#00FF00' : '#FF0000'; // Green if valid, Red if ignored
                  ctx.moveTo(x0, y0);
                  ctx.lineTo(x1, y1);
                  ctx.lineTo(x2, y2);
                  ctx.lineTo(x3, y3);
                  ctx.closePath();
                  ctx.stroke();

                  // Draw Center text
                  const centerX = (x0 + x1 + x2 + x3) / 4;
                  const centerY = (y0 + y1 + y2 + y3) / 4;

                  ctx.fillStyle = "rgba(0,0,0,0.8)";
                  ctx.fillRect(centerX - 20, centerY - 15, 40, 30);
                  ctx.font = "bold 20px Arial";
                  ctx.fillStyle = "white";
                  ctx.textAlign = "center";
                  ctx.fillText(String(id), centerX, centerY + 8);

                  if (VALID_MARKER_IDS.includes(id)) {
                    foundIds.push(id);

                    // Trigger Sound logic
                    const lastTime = lastPlayedTime.current.get(id) || 0;
                    if (now - lastTime > SOUND_COOLDOWN_MS) {
                      console.log(`Triggering sound for ID: ${id}`);
                      audioService.play(currentPackId, id);
                      lastPlayedTime.current.set(id, now);

                      // Trigger visual flash
                      setLastTriggeredId(id);
                      setTimeout(() => setLastTriggeredId(null), 300);
                    }
                  }
               }
             }
           }

           setDetectedIds(foundIds);

           // Update Stats
           const endTime = performance.now();
           setDebugStats(prev => ({
             ...prev,
             processingTime: Math.round(endTime - startTime),
             fps: Math.round(1000 / (endTime - startTime || 1)) // Instant FPS approx
           }));

           src.delete();
           gray.delete();
           dictionary.delete();
           markerIds.delete();
           markerCorners.delete();
           params.delete();
        }
      } catch (e) {
        console.error("CV Detection Crash:", e);
      }
    }

    requestRef.current = requestAnimationFrame(processFrame);
  }, [cvReady, currentPackId, debugMode]);

  useEffect(() => {
    if (cvReady) {
       requestRef.current = requestAnimationFrame(processFrame);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [cvReady, processFrame]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">

      {/* Video Layer */}
      <video 
        ref={videoRef} 
        className="absolute w-full h-full object-cover" 
        playsInline 
        muted 
      />

      {/* Overlay Canvas */}
      <canvas 
        ref={canvasRef}
        className="absolute w-full h-full pointer-events-none object-cover"
      />

      {/* Visual Feedback Flash */}
      <div 
        className={`absolute inset-0 border-8 border-green-500 pointer-events-none transition-opacity duration-300 ${lastTriggeredId ? 'opacity-100' : 'opacity-0'}`} 
        style={{ boxShadow: 'inset 0 0 50px #22c55e' }}
      />

      {/* Visual Feedback Text Center */}
      {lastTriggeredId && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-50">
          <div className="bg-green-500 text-white font-bold text-6xl px-8 py-4 rounded-3xl shadow-2xl animate-bounce">
            #{lastTriggeredId}
          </div>
        </div>
      )}

      {/* Initialization Spinner */}
      {(!cvReady) && (
         <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900/90 z-50 text-white">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-t-blue-500 border-white/20 mb-4"></div>
            <p className="font-mono text-sm">Initializing OpenCV...</p>
         </div>
      )}

      {/* Error Message */}
      {cameraError && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900 z-50 p-6 text-center">
           <p className="text-red-500 font-bold text-xl mb-2">Camera Error</p>
           <p className="text-gray-300 mb-6">{cameraError}</p>
           <button onClick={onBack} className="bg-white text-black px-6 py-3 rounded-full font-bold">
             Back to Home
           </button>
        </div>
      )}

      {/* Controls Overlay */}
      <div className="absolute top-0 left-0 right-0 z-40 p-4 pt-safe flex justify-between items-start">
        <button 
          onClick={onBack}
          className="w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md rounded-full text-white hover:bg-black/60 transition-all"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
        </button>

        <div className="flex gap-2">
           {/* Debug Toggle */}
           <button 
             onClick={() => setDebugMode(!debugMode)}
             className={`px-4 h-12 rounded-full font-mono text-xs font-bold backdrop-blur-md ${debugMode ? 'bg-green-500/20 text-green-400 border border-green-500/50' : 'bg-black/40 text-gray-400'}`}
           >
             {debugMode ? 'DEBUG ON' : 'DEBUG OFF'}
           </button>

           {/* Camera Flip */}
           <button 
             onClick={handleSwitchCamera}
             className="w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md rounded-full text-white hover:bg-black/60"
           >
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
           </button>
        </div>
      </div>

      {/* DEBUG PANEL */}
      {debugMode && (
        <div className="absolute bottom-safe left-4 right-4 z-30 pointer-events-none">
          <div className="bg-black/80 backdrop-blur text-green-400 p-4 rounded-xl font-mono text-xs shadow-lg border border-gray-800">
             <div className="grid grid-cols-2 gap-y-1">
               <span className="text-gray-500">RES:</span> <span>{debugStats.resolution}</span>
               <span className="text-gray-500">PROC:</span> <span>{debugStats.processingTime}ms</span>
               <span className="text-gray-500">DETECTED:</span> <span className="text-white font-bold">{detectedIds.length > 0 ? detectedIds.join(', ') : 'NONE'}</span>
             </div>
             <div className="mt-2 pt-2 border-t border-gray-700 text-gray-500 text-[10px] leading-tight">
               Looking for IDs: {VALID_MARKER_IDS.slice(0, 8).join(', ')}...
               <br/>
               If detection fails: improve lighting, hold marker steady, ensure white border.
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

