               <div className="h-full bg-blue-600 animate-pulse w-1/2"></div>
            </div>
            <p className="text-xs text-gray-600 mt-4">Downloading 8MB OpenCV engine...</p>
         </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
