  const processingCanvasRef = useRef<HTMLCanvasElement | null>(null);

  const [cvReady, setCvReady] = useState(false);
  const [detectedIds, setDetectedIds] = useState<number[]>([]);
  const [debugMode, setDebugMode] = useState(true);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('environment');
  const [lastTriggeredId, setLastTriggeredId] = useState<number | null>(null);
  const [debugLog, setDebugLog] = useState<string[]>([]);
  const [loadingMsg, setLoadingMsg] = useState("Initializing Vision...");

  const [debugStats, setDebugStats] = useState({ fps: 0, processingTime: 0, resolution: '0x0' });

  const requestRef = useRef<number | null>(null);
  const lastScanTime = useRef<number>(0);
  const lastPlayedTime = useRef<Map<number, number>>(new Map());
  const streamRef = useRef<MediaStream | null>(null);

  const addLog = (msg: string) => {
    setDebugLog(prev => [msg, ...prev].slice(0, 10));
    console.log(`[APP] ${msg}`);
  };

  // Initialize OpenCV (Standard 4.5.5 detection)
  useEffect(() => {
    let attempts = 0;
    const checkCv = setInterval(() => {
      attempts++;
      // Check for main object
      if (window.cv && window.cv.getBuildInformation) {
        // Check for specific ArUco functions availability
        try {
          if (window.cv.getPredefinedDictionary) {
             addLog("OpenCV Ready (Standard Mode)");
             setCvReady(true);
             clearInterval(checkCv);
          } else if (window.cv.aruco) {
             addLog("OpenCV Ready (Contrib Mode)");
             setCvReady(true);
             clearInterval(checkCv);
          } else {
             if (attempts > 10) addLog("Waiting for ArUco symbols...");
          }
        } catch (e) {
          console.error(e);
        }
      }

      if (attempts > 40) { // 20 seconds timeout
         setLoadingMsg("Timeout loading OpenCV. Check connection.");
         clearInterval(checkCv);
      }
    }, 500);
    return () => clearInterval(checkCv);
  }, []);

  // Preload sounds
  useEffect(() => {
    audioService.preloadPack(currentPackId);
  }, [currentPackId]);

  // Camera Management
  useEffect(() => {
    const startCamera = async () => {
      setCameraError(null);

      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }

      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: { ideal: facingMode },
            width: { ideal: 1280 }, // Lower resolution for better stability on start
            height: { ideal: 720 }
          },
          audio: false,
        });

        streamRef.current = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.onloadedmetadata = () => {
             videoRef.current?.play();
             if(videoRef.current) {
               setDebugStats(prev => ({ 
                 ...prev, 
                 resolution: `${videoRef.current?.videoWidth}x${videoRef.current?.videoHeight}` 
               }));
             }
          };
        }
      } catch (err) {
        console.error("Camera Error:", err);
        setCameraError("Camera access denied.");
        addLog("Cam Error: " + err);
      }
    };

    startCamera();

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [facingMode]);

  const handleSwitchCamera = () => {
    setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
  };

  const handleSimulate = () => {
    // Simulate detecting ID 13
    addLog("[TEST] Simulating Marker #13");
    triggerMarker(13);
  };

  const triggerMarker = (id: number) => {
    const now = performance.now();
    const lastTime = lastPlayedTime.current.get(id) || 0;

    // Always trigger visual
    setLastTriggeredId(id);
    setTimeout(() => setLastTriggeredId(null), 300);

    if (now - lastTime > SOUND_COOLDOWN_MS) {
      addLog(`MATCH ID ${id} !!!`);
      audioService.play(currentPackId, id);
      lastPlayedTime.current.set(id, now);
    }
  };

  // Main Detection Loop
  const processFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current || !cvReady || !window.cv) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });

    if (video.readyState !== video.HAVE_ENOUGH_DATA || !ctx) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    if (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const now = performance.now();

    if (now - lastScanTime.current > DETECTION_INTERVAL_MS) {
      const startTime = performance.now();
      lastScanTime.current = now;

      try {
        const cv = window.cv;
        if (!processingCanvasRef.current) processingCanvasRef.current = document.createElement('canvas');
        const pCanvas = processingCanvasRef.current;

        // Use 480p width for processing - better performance on mobile JS
        const procWidth = 480; 
        const scale = procWidth / video.videoWidth;
        const procHeight = video.videoHeight * scale;

        if (pCanvas.width !== procWidth) {
           pCanvas.width = procWidth;
           pCanvas.height = procHeight;
        }

        const pCtx = pCanvas.getContext('2d', { willReadFrequently: true });
        if (pCtx) {
           pCtx.drawImage(video, 0, 0, procWidth, procHeight);

           let src = cv.imread(pCanvas);
           let gray = new cv.Mat();
           cv.cvtColor(src, gray, cv.COLOR_RGBA2GRAY, 0);

           // --- ROBUST INITIALIZATION ---
           let dictionary = null;
           // In 4.5.5, it's usually on the main object
           if (cv.getPredefinedDictionary) {
             dictionary = cv.getPredefinedDictionary(cv.DICT_4X4_250);
           } else if (cv.aruco && cv.aruco.getPredefinedDictionary) {
             dictionary = cv.aruco.getPredefinedDictionary(cv.aruco.DICT_4X4_250);
           } else {
             throw new Error("API Mismatch: getPredefinedDictionary not found");
           }

           let markerCorners = new cv.MatVector();
           let markerIds = new cv.Mat();
           let params = new cv.DetectorParameters();

           // Tuning
           params.adaptiveThreshWinSizeMin = 3;
           params.adaptiveThreshWinSizeMax = 23;
           params.adaptiveThreshWinSizeStep = 10;
           params.minMarkerPerimeterRate = 0.03; // Detect smaller markers

           // Call detectMarkers (Handles both namespaces)
           if (cv.detectMarkers) {
             cv.detectMarkers(gray, dictionary, markerCorners, markerIds, params);
           } else if (cv.aruco && cv.aruco.detectMarkers) {
             cv.aruco.detectMarkers(gray, dictionary, markerCorners, markerIds, params);
           } else {
             throw new Error("API Mismatch: detectMarkers not found");
           }

           const foundIds: number[] = [];

           if (markerIds.rows > 0) {
             for (let i = 0; i < markerIds.rows; i++) {
               const id = markerIds.data32S[i];

               // Draw visualization
               const corners = markerCorners.get(i);
               const invScale = 1 / scale;

               const x0 = corners.data32F[0] * invScale;
               const y0 = corners.data32F[1] * invScale;
               const x1 = corners.data32F[2] * invScale;
               const y1 = corners.data32F[3] * invScale;
               const x2 = corners.data32F[4] * invScale;
               const y2 = corners.data32F[5] * invScale;
               const x3 = corners.data32F[6] * invScale;
               const y3 = corners.data32F[7] * invScale;

               const isValid = VALID_MARKER_IDS.includes(id);

               if (debugMode || isValid) {
                   ctx.beginPath();
                   ctx.lineWidth = isValid ? 5 : 2;
                   ctx.strokeStyle = isValid ? '#22c55e' : '#f59e0b';
                   ctx.moveTo(x0, y0);
                   ctx.lineTo(x1, y1);
                   ctx.lineTo(x2, y2);
                   ctx.lineTo(x3, y3);
                   ctx.closePath();
                   ctx.stroke();

                   // Label
                   const centerX = (x0 + x1 + x2 + x3) / 4;
                   const centerY = (y0 + y1 + y2 + y3) / 4;

                   ctx.font = "bold 24px monospace";
                   ctx.fillStyle = isValid ? "#22c55e" : "#f59e0b";
                   ctx.strokeStyle = "black";
                   ctx.lineWidth = 3;
                   ctx.strokeText(`${id}`, centerX, centerY);
                   ctx.fillText(`${id}`, centerX, centerY);
               }

               if (isValid) {
                 foundIds.push(id);
                 triggerMarker(id);
               }
             }
           }

           setDetectedIds(foundIds);

           const endTime = performance.now();
           setDebugStats(prev => ({
             ...prev,
             processingTime: Math.round(endTime - startTime),
             fps: Math.round(1000 / (endTime - startTime || 1))
           }));

           // Cleanup
           src.delete();
           gray.delete();
           dictionary.delete();
           markerIds.delete();
           markerCorners.delete();
           params.delete();
        }
      } catch (e: any) {
        if (!debugLog.includes("Scan Error: " + e.message)) {
             addLog("Scan Error: " + e.message);
        }
      }
    }

    requestRef.current = requestAnimationFrame(processFrame);
  }, [cvReady, currentPackId, debugMode, debugLog]);

  useEffect(() => {
    if (cvReady) {
       requestRef.current = requestAnimationFrame(processFrame);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [cvReady, processFrame]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">
      <video ref={videoRef} className="absolute w-full h-full object-cover" playsInline muted />
      <canvas ref={canvasRef} className="absolute w-full h-full pointer-events-none object-cover" />

      {/* Trigger Flash */}
      <div className={`absolute inset-0 bg-green-500 pointer-events-none transition-opacity duration-100 ${lastTriggeredId ? 'opacity-30' : 'opacity-0'}`} />

      {/* HUD Controls */}
      <div className="absolute top-0 left-0 right-0 z-40 p-4 pt-safe flex justify-between items-start pointer-events-none">
        <button onClick={onBack} className="pointer-events-auto w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md rounded-full text-white">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
        </button>

        <div className="flex gap-2 pointer-events-auto">
           {debugMode && (
             <button onClick={handleSimulate} className="px-3 h-12 rounded-full font-bold bg-blue-600/80 text-white backdrop-blur-md text-xs shadow-lg animate-pulse">
               SIMULATE #13
             </button>
           )}
           <button onClick={() => setDebugMode(!debugMode)} className={`px-4 h-12 rounded-full font-bold backdrop-blur-md text-xs shadow-lg transition-colors ${debugMode ? 'bg-green-600 text-white' : 'bg-black/40 text-gray-400'}`}>
             {debugMode ? 'DEBUG' : 'DEBUG'}
           </button>
           <button onClick={handleSwitchCamera} className="w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md rounded-full text-white shadow-lg">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
           </button>
        </div>
      </div>

      {/* Debug Panel */}
      {debugMode && (
        <div className="absolute bottom-safe left-4 right-4 z-30 pointer-events-none flex flex-col gap-2">
          <div className="bg-black/80 backdrop-blur text-green-400 p-4 rounded-xl font-mono text-xs shadow-lg border border-gray-800">
             <div className="flex justify-between items-center mb-2 pb-2 border-b border-gray-700">
               <span className="font-bold text-white">OPENCV 4.5.5</span>
               <span className={cvReady ? "text-green-500" : "text-yellow-500"}>{cvReady ? "READY" : "LOADING..."}</span>
             </div>
             <div className="grid grid-cols-2 gap-y-1">
               <span className="text-gray-500">RES:</span> <span>{debugStats.resolution}</span>
               <span className="text-gray-500">PROC:</span> <span>{debugStats.processingTime}ms ({debugStats.fps} FPS)</span>
               <span className="text-gray-500">LAST:</span> <span className="text-white font-bold">{lastTriggeredId || '-'}</span>
             </div>
          </div>

          <div className="bg-black/80 backdrop-blur p-2 rounded-xl border border-gray-800 pointer-events-auto max-h-40 overflow-y-auto shadow-lg">
             {debugLog.map((log, i) => (
               <div key={i} className="text-[10px] font-mono text-gray-300 border-b border-gray-800/50 pb-1 mb-1 last:border-0 last:mb-0 break-words">{log}</div>
             ))}
          </div>
        </div>
      )}

      {/* Loader */}
      {!cvReady && (
         <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900 z-50 text-white p-6 text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-t-blue-500 border-gray-700 mb-6"></div>
            <h2 className="text-xl font-bold mb-2">Vision Engine</h2>
            <p className="font-mono text-sm text-gray-400 mb-4">{loadingMsg}</p>
         </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { audioService } from '../services/audioService';
import { VALID_MARKER_IDS, DETECTION_INTERVAL_MS, SOUND_COOLDOWN_MS } from '../constants';

interface ScannerProps {
  currentPackId: string;
  onBack: () => void;
}

export const Scanner: React.FC<ScannerProps> = ({ currentPackId, onBack }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const processingCanvasRef = useRef<HTMLCanvasElement | null>(null);

  const [cvReady, setCvReady] = useState(false);
  const [detectedIds, setDetectedIds] = useState<number[]>([]);
  const [debugMode, setDebugMode] = useState(true);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('environment');
  const [lastTriggeredId, setLastTriggeredId] = useState<number | null>(null);
  const [debugLog, setDebugLog] = useState<string[]>([]);
  const [loadingMsg, setLoadingMsg] = useState("Loading Vision Engine...");

  const [debugStats, setDebugStats] = useState({ fps: 0, processingTime: 0, resolution: '0x0' });

  const requestRef = useRef<number | null>(null);
  const lastScanTime = useRef<number>(0);
  const lastPlayedTime = useRef<Map<number, number>>(new Map());
  const streamRef = useRef<MediaStream | null>(null);
  const initializationTriggered = useRef(false);

  const addLog = (msg: string) => {
    setDebugLog(prev => [msg, ...prev].slice(0, 10));
    console.log(`[APP] ${msg}`);
  };

  // Initialize OpenCV 4.9.0 (Async Factory Pattern)
  useEffect(() => {
    let checkTimer: any = null;

    const initOpenCV = async () => {
      if (initializationTriggered.current) return;

      let attempts = 0;
      checkTimer = setInterval(async () => {
        attempts++;
        if (window.cv) {
          try {
            // Case 1: cv is already a fully loaded object
            if (window.cv.getBuildInformation) {
              addLog("OpenCV Object Found");
              if (window.cv.aruco) {
                addLog("ArUco Module Ready!");
                setCvReady(true);
                clearInterval(checkTimer);
              } else {
                addLog("WAIT: ArUco not yet attached...");
              }
            } 
            // Case 2: cv is a Factory Function (common in Emscripten builds like @techstark)
            else if (typeof window.cv === 'function' && !initializationTriggered.current) {
              addLog("Initializing OpenCV WASM...");
              initializationTriggered.current = true;
              setLoadingMsg("Compiling WASM...");

              try {
                // Execute the factory to get the real instance
                const cvInstance = await window.cv();
                window.cv = cvInstance;
                addLog("WASM Compiled.");
              } catch (e) {
                addLog("WASM Init Failed: " + e);
                initializationTriggered.current = false; // Retry
              }
            }
          } catch (e: any) {
            addLog("Init check error: " + e.message);
          }
        } else {
          if (attempts % 10 === 0) addLog("Waiting for script download...");
        }

        if (attempts > 60) { // 30 seconds
           setLoadingMsg("Timeout. Reload page?");
           clearInterval(checkTimer);
        }
      }, 500);
    };

    initOpenCV();

    return () => {
      if (checkTimer) clearInterval(checkTimer);
    };
  }, []);

  // Preload sounds
  useEffect(() => {
    audioService.preloadPack(currentPackId);
  }, [currentPackId]);

  // Camera Management
  useEffect(() => {
    const startCamera = async () => {
      setCameraError(null);

      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }

      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: { ideal: facingMode },
            width: { ideal: 1920 },
            height: { ideal: 1080 }
          },
          audio: false,
        });

        streamRef.current = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.onloadedmetadata = () => {
             videoRef.current?.play();
             if(videoRef.current) {
               setDebugStats(prev => ({ 
                 ...prev, 
                 resolution: `${videoRef.current?.videoWidth}x${videoRef.current?.videoHeight}` 
               }));
             }
          };
        }
      } catch (err) {
        console.error("Camera Error:", err);
        setCameraError("Camera access denied.");
        addLog("Cam Error: " + err);
      }
    };

    startCamera();

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [facingMode]);

  const handleSwitchCamera = () => {
    setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
  };

  const handleSimulate = () => {
    addLog("[TEST] Simulating Marker #13");
    triggerMarker(13);
  };

  const triggerMarker = (id: number) => {
    const now = performance.now();
    const lastTime = lastPlayedTime.current.get(id) || 0;

    setLastTriggeredId(id);
    setTimeout(() => setLastTriggeredId(null), 300);

    if (now - lastTime > SOUND_COOLDOWN_MS) {
      addLog(`MATCH ID ${id} !!!`);
      audioService.play(currentPackId, id);
      lastPlayedTime.current.set(id, now);
    }
  };

  // Main Detection Loop
  const processFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current || !cvReady || !window.cv || !window.cv.aruco) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });

    if (video.readyState !== video.HAVE_ENOUGH_DATA || !ctx) {
      requestRef.current = requestAnimationFrame(processFrame);
      return;
    }

    if (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const now = performance.now();

    if (now - lastScanTime.current > DETECTION_INTERVAL_MS) {
      const startTime = performance.now();
      lastScanTime.current = now;

      try {
        const cv = window.cv;
        const aruco = cv.aruco;

        if (!processingCanvasRef.current) processingCanvasRef.current = document.createElement('canvas');
        const pCanvas = processingCanvasRef.current;

        // Use higher resolution for 4.9.0 detection
        const procWidth = 640; 
        const scale = procWidth / video.videoWidth;
        const procHeight = video.videoHeight * scale;

        if (pCanvas.width !== procWidth) {
           pCanvas.width = procWidth;
           pCanvas.height = procHeight;
        }

        const pCtx = pCanvas.getContext('2d', { willReadFrequently: true });
        if (pCtx) {
           pCtx.drawImage(video, 0, 0, procWidth, procHeight);

           let src = cv.imread(pCanvas);

           // Correct 4.9.0 ArUco Initialization
           // 1. Create Dictionary
           let dictionary = new aruco.Dictionary(aruco.DICT_4X4_250);

           // 2. Create Detector Params
           let params = new aruco.DetectorParameters();
           params.adaptiveThreshWinSizeMin = 3;
           params.adaptiveThreshWinSizeMax = 23;
           params.adaptiveThreshWinSizeStep = 10;
           params.minMarkerPerimeterRate = 0.05;

           // 3. Prepare Output Containers
           let markerCorners = new cv.MatVector();
           let markerIds = new cv.Mat();
           let rejected = new cv.MatVector();

           // 4. Detect
           aruco.detectMarkers(src, dictionary, markerCorners, markerIds, params, rejected);

           const foundIds: number[] = [];

           if (markerIds.rows > 0) {
             for (let i = 0; i < markerIds.rows; i++) {
               const id = markerIds.data32S[i];

               // Draw visualization
               const corners = markerCorners.get(i);
               const invScale = 1 / scale;

               const x0 = corners.data32F[0] * invScale;
               const y0 = corners.data32F[1] * invScale;
               const x1 = corners.data32F[2] * invScale;
               const y1 = corners.data32F[3] * invScale;
               const x2 = corners.data32F[4] * invScale;
               const y2 = corners.data32F[5] * invScale;
               const x3 = corners.data32F[6] * invScale;
               const y3 = corners.data32F[7] * invScale;

               const isValid = VALID_MARKER_IDS.includes(id);

               if (debugMode || isValid) {
                   ctx.beginPath();
                   ctx.lineWidth = isValid ? 5 : 2;
                   ctx.strokeStyle = isValid ? '#22c55e' : '#f59e0b';
                   ctx.moveTo(x0, y0);
                   ctx.lineTo(x1, y1);
                   ctx.lineTo(x2, y2);
                   ctx.lineTo(x3, y3);
                   ctx.closePath();
                   ctx.stroke();

                   const centerX = (x0 + x1 + x2 + x3) / 4;
                   const centerY = (y0 + y1 + y2 + y3) / 4;

                   ctx.font = "bold 20px monospace";
                   ctx.fillStyle = isValid ? "#22c55e" : "#f59e0b";
                   ctx.fillText(`ID:${id}`, centerX, centerY);
               }

               if (isValid) {
                 foundIds.push(id);
                 triggerMarker(id);
               }
             }
           }

           setDetectedIds(foundIds);

           const endTime = performance.now();
           setDebugStats(prev => ({
             ...prev,
             processingTime: Math.round(endTime - startTime),
             fps: Math.round(1000 / (endTime - startTime || 1))
           }));

           // Cleanup
           src.delete();
           dictionary.delete();
           markerIds.delete();
           markerCorners.delete();
           rejected.delete();
           params.delete();
        }
      } catch (e: any) {
        if (!debugLog.includes("Scan Error: " + e.message)) {
             addLog("Scan Error: " + e.message);
        }
      }
    }

    requestRef.current = requestAnimationFrame(processFrame);
  }, [cvReady, currentPackId, debugMode, debugLog]);

  useEffect(() => {
    if (cvReady) {
       requestRef.current = requestAnimationFrame(processFrame);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [cvReady, processFrame]);

  return (
    <div className="relative w-full h-full bg-black overflow-hidden">
      <video ref={videoRef} className="absolute w-full h-full object-cover" playsInline muted />
      <canvas ref={canvasRef} className="absolute w-full h-full pointer-events-none object-cover" />

      {/* Trigger Flash */}
      <div className={`absolute inset-0 bg-green-500 pointer-events-none transition-opacity duration-100 ${lastTriggeredId ? 'opacity-30' : 'opacity-0'}`} />

      {/* HUD Controls */}
      <div className="absolute top-0 left-0 right-0 z-40 p-4 pt-safe flex justify-between items-start pointer-events-none">
        <button onClick={onBack} className="pointer-events-auto w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md rounded-full text-white">
